"use client";

import { useEffect, useRef, useState } from "react";
import { useWizardStore, type AspectRatio } from "@/store/wizard";
import { t } from "@/lib/i18n";
import * as fabric from "fabric";

const ASPECT_SIZES: Record<AspectRatio, { w: number; h: number }> = {
  "1:1": { w: 800, h: 800 },
  "3:4": { w: 800, h: 1067 },
  "4:3": { w: 800, h: 600 },
  "4:5": { w: 800, h: 1000 },
  "5:4": { w: 800, h: 640 },
  "9:16": { w: 720, h: 1280 },
  "16:9": { w: 1280, h: 720 },
};

const TEXT_TEMPLATE_STYLES = [
  { fontSize: 42, color: "#ffffff" },
  { fontSize: 38, color: "#f59e0b" },
  { fontSize: 44, color: "#ef4444" },
  { fontSize: 36, color: "#10b981" },
];

export default function StepCanvas() {
  const store = useWizardStore();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fabricRef = useRef<fabric.Canvas | null>(null);
  const [activeTemplate, setActiveTemplate] = useState<number | null>(null);
  const [canvasReady, setCanvasReady] = useState(false);

  const aspectRatio = store.selectedAspectRatio;
  const size = ASPECT_SIZES[aspectRatio];

  useEffect(() => {
    if (!canvasRef.current || !store.generatedImageUrl) return;

    const canvas = new fabric.Canvas(canvasRef.current, {
      width: size.w,
      height: size.h,
      backgroundColor: "#111",
    });
    fabricRef.current = canvas;
    setCanvasReady(false);

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const fabricImg = new fabric.FabricImage(img, {
        selectable: false,
        evented: false,
      });

      const scaleX = size.w / img.naturalWidth;
      const scaleY = size.h / img.naturalHeight;
      const scale = Math.max(scaleX, scaleY);

      fabricImg.set({
        scaleX: scale,
        scaleY: scale,
        left: size.w / 2,
        top: size.h / 2,
        originX: "center",
        originY: "center",
      });

      canvas.add(fabricImg);
      canvas.sendObjectToBack(fabricImg);
      canvas.renderAll();
      setCanvasReady(true);
    };
    img.src = store.generatedImageUrl;

    return () => {
      canvas.dispose();
    };
  }, [store.generatedImageUrl, aspectRatio, size.w, size.h]);

  const addTextTemplate = (idx: number) => {
    const canvas = fabricRef.current;
    if (!canvas || !canvasReady) return;

    const existingTexts = canvas.getObjects().filter((o) => o.type === "textbox");
    existingTexts.forEach((o) => canvas.remove(o));

    const style = TEXT_TEMPLATE_STYLES[idx];
    const label = t.canvas.templates[idx];
    const text = new fabric.Textbox(label.toUpperCase(), {
      left: size.w / 2,
      top: size.h * 0.85,
      originX: "center",
      originY: "center",
      fontSize: style.fontSize,
      fill: style.color,
      fontFamily: "Arial",
      fontWeight: "bold",
      textAlign: "center",
      width: size.w * 0.8,
      shadow: new fabric.Shadow({ color: "rgba(0,0,0,0.7)", blur: 8, offsetX: 2, offsetY: 2 }),
    });
    canvas.add(text);
    canvas.setActiveObject(text);
    canvas.renderAll();
    setActiveTemplate(idx);
  };

  const changeAspect = (ratio: AspectRatio) => {
    store.setAspectRatio(ratio);
  };

  const exportCanvas = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    const dataUrl = canvas.toDataURL({ format: "png", quality: 1, multiplier: 2 });
    const a = document.createElement("a");
    a.href = dataUrl;
    a.download = `foodsocial_${Date.now()}.png`;
    a.click();
  };

  const displayScale = Math.min(400 / size.w, 600 / size.h, 1);
  const displayW = size.w * displayScale;
  const displayH = size.h * displayScale;

  return (
    <div className="flex flex-col lg:flex-row gap-6">
      <div className="flex-1 flex justify-center items-start">
        <div
          className="border border-gray-700 rounded-xl overflow-hidden"
          style={{ width: displayW, height: displayH }}
        >
          <canvas
            ref={canvasRef}
            style={{
              width: displayW,
              height: displayH,
              display: "block",
            }}
          />
        </div>
      </div>

      <div className="w-full lg:w-72 flex flex-col gap-6">
        <div>
          <h3 className="text-sm font-semibold text-gray-400 mb-2 uppercase tracking-wider">
            {t.canvas.aspectRatio}
          </h3>
          <div className="flex flex-wrap gap-2">
            {(Object.keys(ASPECT_SIZES) as AspectRatio[]).map((ratio) => (
              <button
                key={ratio}
                onClick={() => changeAspect(ratio)}
                aria-label={`Proporción ${ratio}`}
                className={`px-3 py-2 rounded-lg text-sm cursor-pointer transition-colors duration-200 ${
                  aspectRatio === ratio
                    ? "bg-amber-600 text-white"
                    : "bg-gray-800 text-gray-400 hover:bg-gray-700"
                }`}
              >
                {ratio}
              </button>
            ))}
          </div>
        </div>

        <div>
          <h3 className="text-sm font-semibold text-gray-400 mb-2 uppercase tracking-wider">
            {t.canvas.textOverlay}
          </h3>
          <div className="flex flex-col gap-2">
            {t.canvas.templates.map((label, i) => (
              <button
                key={label}
                onClick={() => addTextTemplate(i)}
                aria-label={label}
                disabled={!canvasReady}
                className={`px-3 py-2 rounded-lg text-sm text-left cursor-pointer transition-colors duration-200 disabled:opacity-50 disabled:cursor-not-allowed ${
                  activeTemplate === i
                    ? "bg-amber-600/20 ring-1 ring-amber-500 text-amber-400"
                    : "bg-gray-800 text-gray-300 hover:bg-gray-700"
                }`}
              >
                {label}
              </button>
            ))}
          </div>
        </div>

        <button
          onClick={exportCanvas}
          disabled={!canvasReady}
          className="mt-auto px-4 py-3 bg-amber-600 text-white rounded-xl font-semibold cursor-pointer hover:bg-amber-500 transition-colors duration-200 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {t.canvas.download}
        </button>
      </div>
    </div>
  );
}
